  1→import supabase from "./supabase.js";
  2→import { createLRUCache } from "../utils/LRUCache.js";
  3→
  4→// ── In-memory LRU cache for related posts ──
  5→const relatedCache = createLRUCache(200, 10 * 60 * 1000); // 200 entries, 10min TTL
  6→const getRelatedCached = (key) => relatedCache.get(key);
  7→const setRelatedCached = (key, value) => relatedCache.set(key, value);
  8→
  9→const CONFIDENCE_TIERS = {
 10→    high:   { threshold: 0.60, maxResults: 5, label: 'high' },
 11→    medium: { threshold: 0.48, maxResults: 3, label: 'medium' },
 12→    low:    { threshold: 0.38, maxResults: 2, label: 'low' },
 13→};
 14→
 15→let _dynamicFloorCache = { value: null, ts: 0 };
 16→const DYNAMIC_FLOOR_TTL_MS = 5 * 60 * 1000; // 5 minutes
 17→
 18→async function getDynamicFloor() {
 19→    if (_dynamicFloorCache.value !== null && Date.now() - _dynamicFloorCache.ts < DYNAMIC_FLOOR_TTL_MS) {
 20→        return _dynamicFloorCache.value;
 21→    }
 22→
 23→    const { count, error } = await supabase
 24→        .from('journals')
 25→        .select('id', { count: 'exact', head: true })
 26→        .eq('privacy', 'public')
 27→        .not('embeddings', 'is', null);
 28→
 29→    if (error) {
 30→        console.error('getDynamicFloor count error:', error.message);
 31→        return _dynamicFloorCache.value ?? 0.30;
 32→    }
 33→
 34→    let floor;
 35→    if (count < 500)  floor = 0.35;
 36→    else if (count < 2000) floor = 0.40;
 37→    else floor = 0.45;
 38→
 39→    _dynamicFloorCache = { value: floor, ts: Date.now() };
 40→    return floor;
 41→}
 42→
 43→function getConfidenceTier(topSimilarity) {
 44→    if (topSimilarity >= CONFIDENCE_TIERS.high.threshold)   return CONFIDENCE_TIERS.high;
 45→    if (topSimilarity >= CONFIDENCE_TIERS.medium.threshold) return CONFIDENCE_TIERS.medium;
 46→    if (topSimilarity >= CONFIDENCE_TIERS.low.threshold)    return CONFIDENCE_TIERS.low;
 47→    return null;
 48→}
 49→
 50→export async function getRelatedPostsService(journalId) {
 51→    const cached = getRelatedCached(journalId);
 52→    if (cached) return cached;
 53→
 54→    const dynamicFloor = await getDynamicFloor();
 55→
 56→    // First attempt with dynamic floor
 57→    let { data, error } = await supabase.rpc('find_related_posts', {
 58→        source_post_id: journalId,
 59→        match_count: 8,
 60→        similarity_floor: dynamicFloor,
 61→        recency_days: 365,
 62→    });
 63→
 64→    if (error) {
 65→        throw { status: 500, error: 'Failed to find related posts: ' + error.message };
 66→    }
 67→
 68→    // Fallback: if < 2 results, try with a lower floor
 69→    if (!data || data.length < 2) {
 70→        const lowerFloor = Math.max(dynamicFloor - 0.03, 0.30);
 71→        if (lowerFloor < dynamicFloor) {
 72→            const fallback = await supabase.rpc('find_related_posts', {
 73→                source_post_id: journalId,
 74→                match_count: 8,
 75→                similarity_floor: lowerFloor,
 76→                recency_days: 365,
 77→            });
 78→            if (!fallback.error && fallback.data && fallback.data.length >= 2) {
 79→                data = fallback.data;
 80→            }
 81→        }
 82→    }
 83→
 84→    // Never show fewer than 2 results
 85→    if (!data || data.length < 2) {
 86→        return { posts: [], confidence: 'none', topSimilarity: 0 };
 87→    }
 88→
 89→    const topSimilarity = data[0]?.semantic_similarity || 0;
 90→    const tier = getConfidenceTier(topSimilarity);
 91→
 92→    if (!tier) {
 93→        return { posts: [], confidence: 'none', topSimilarity };
 94→    }
 95→
 96→    // Cap results by confidence tier
 97→    const cappedPosts = data.slice(0, tier.maxResults);
 98→
 99→    // Ensure we still have at least 2 after capping
100→    if (cappedPosts.length < 2) {
101→        return { posts: [], confidence: 'none', topSimilarity };
102→    }
103→
104→    const result = {
105→        posts: cappedPosts,
106→        confidence: tier.label,
107→        topSimilarity,
108→    };
109→    setRelatedCached(journalId, result);
110→    return result;
111→}
