169→                        </label>
170→                        <input
171→                            type="text"
172→                            className="story-editor-input"
173→                            value={title}
174→                            onChange={(e) => setTitle(e.target.value)}
175→                            maxLength={200}
176→                            placeholder="Give your story a title"
177→                            required
178→                        />
179→                    </div>
180→
181→                    {/* Description */}
182→                    <div className="story-editor-field">
183→                        <label className="story-editor-label">
184→                            Description
185→                            <span className="story-editor-counter">{description.length}/2000</span>
186→                        </label>
187→                        <textarea
188→                            className="story-editor-textarea"
189→                            value={description}
190→                            onChange={(e) => setDescription(e.target.value)}
191→                            maxLength={2000}
192→                            placeholder="What is your story about?"
193→                            rows={4}
194→                        />
195→                    </div>
196→
197→                    {/* Status & Privacy */}
198→                    <div className="story-editor-row">
199→                        <div className="story-editor-field story-editor-field-half">
200→                            <label className="story-editor-label">Status</label>
201→                            <select
202→                                className="story-editor-select"
203→                                value={status}
204→                                onChange={(e) => setStatus(e.target.value)}
205→                            >
206→                                <option value="ongoing">Ongoing</option>
207→                                <option value="completed">Completed</option>
208→                                <option value="hiatus">Hiatus</option>
209→                            </select>
210→                        </div>
211→                        <div className="story-editor-field story-editor-field-half">
212→                            <label className="story-editor-label">Privacy</label>
213→                            <select
214→                                className="story-editor-select"
215→                                value={privacy}
216→                                onChange={(e) => setPrivacy(e.target.value)}
217→                            >
218→                                <option value="public">Public</option>
219→                                <option value="private">Private</option>
220→                            </select>
221→                        </div>
222→                    </div>
223→
224→                    {/* Tags */}
225→                    <div className="story-editor-field">
226→                        <label className="story-editor-label">Tags ({tags.length}/10)</label>
227→                        <div className="story-editor-tags-container">
228→                            {tags.map((tag) => (
229→                                <span key={tag} className="story-editor-tag">
230→                                    {tag}
231→                                    <button
232→                                        type="button"
233→                                        className="story-editor-tag-remove"
234→                                        onClick={() => handleRemoveTag(tag)}
235→                                    >
236→                                        &times;
237→                                    </button>
238→                                </span>
239→                            ))}
240→                            {tags.length < 10 && (
241→                                <input
242→                                    type="text"
243→                                    className="story-editor-tag-input"
244→                                    value={tagInput}
245→                                    onChange={(e) => setTagInput(e.target.value)}
246→                                    onKeyDown={handleTagKeyDown}
247→                                    placeholder="Add a tag..."
248→                                />
249→                            )}
250→                        </div>
251→                        <div className="story-editor-tag-suggestions">
252→                            {TAG_SUGGESTIONS
253→                                .filter(s => !tags.includes(s))
254→                                .slice(0, 8)
255→                                .map((s) => (
256→                                    <button
257→                                        key={s}
258→                                        type="button"
259→                                        className="story-editor-tag-suggestion"
260→                                        onClick={() => handleAddTag(s)}
261→                                    >
262→                                        + {s}
263→                                    </button>
264→                                ))}
265→                        </div>
266→                    </div>
267→
268→                    {/* Submit */}
269→                    <button
270→                        type="submit"
271→                        className="story-editor-submit"
272→                        disabled={!title.trim() || isSaving}
273→                    >
274→                        {isSaving ? (
275→                            <BeatLoader size={8} color="var(--bg-primary)" />
276→                        ) : (
277→                            isEdit ? 'Save Changes' : 'Create Story'
278→                        )}
279→                    </button>
280→                </form>
281→            </div>
282→        </motion.div>
283→    );
284→};
285→
286→export default StoryEditor;
