290→        if(Array.isArray(parsed?.pending)){
291→            initial.pending = parsed.pending
292→                .filter((item) => PROFILE_MEDIA_BUCKETS.includes(item?.bucket) && typeof item?.path === 'string' && typeof item?.name === 'string')
293→                .map((item) => ({
