187→export const listVariantPathsForDeletion = (path = '') => {
188→    const descriptor = getVariantPathSet(path);
189→    if(!descriptor.representativePath){
190→        return [];
191→    }
192→
193→    const paths = descriptor.isVariantManaged
194→        ? [
195→            descriptor.thumbnailPath,
196→            descriptor.cardPath,
197→            descriptor.detailPath,
198→            descriptor.originalPath
199→        ]
200→        : [descriptor.representativePath];
201→
202→    return [...new Set(paths.filter(Boolean))];
203→};
