225→export const createMediaResponsePayload = (bucket, urlOrPath = '', usage = 'card') => {
226→    const descriptor = buildVariantDescriptor(bucket, urlOrPath);
227→    if(!descriptor){
228→        return null;
229→    }
230→
231→    return {
